/* MERGE INTO converted: uses UPDATE-if-exists + INSERT pattern */
WITH existing AS (
	SELECT TA_DTKEY
	  FROM TWORK_INFO_TA_DT
	 WHERE CTKEY   = #{ctkey}
	   AND IBHDKEY = #{ibhdkey}
	   AND IBDTKEY = #{ibdtkey}
	   AND QTY > 0
	 ORDER BY TA_DTKEY DESC
	 LIMIT 1
),
updated AS (
	UPDATE TWORK_INFO_TA_DT DT
	   SET QTY = DT.QTY + #{qty}
	  FROM existing e
	 WHERE DT.TA_DTKEY = e.TA_DTKEY
	RETURNING DT.TA_DTKEY
)
INSERT INTO TWORK_INFO_TA_DT (
		 CTKEY
		,TA_DTKEY
		,TA_DTTYPE
		,OWKEY
