UPDATE TWORK_INFO_TA_DT
SET
	WKSTATUS = #{wkstatus}
		, IF_STATUS = #{ifStatus}
		, IF_STATUS_MSG = #{ifStatusMsg}

		, TA_STARTDATE = #{ta_startdate}


		, TA_ENDDATE = #{ta_enddate}


		, WKQTY = #{cfqty}


		, QTY = #{qty}


		, RJQTY = #{rjqty}


		, RES_QTY = #{resQty}


		, RES_IB_FLOOR = #{resIbFloor}


		, TO_LCKEY = #{to_lckey}
		, TO_LCSTORTYPE = #{to_lcstortype}
		, TO_IB_FLOOR = #{to_ib_floor}

  , UPDATEDATE = #{sysdate}
  , UPDATEURKEY = #{updateurkey}
WHERE CTKEY = #{ctkey}
  AND TA_DTKEY = #{ta_dtkey}
  AND TA_HDKEY = #{ta_hdkey}

UPDATE TWORK_INFO_TA_HD A
SET
      WKSTATUS = (SELECT CASE WHEN COUNT(1) = SUM(CASE WKSTATUS WHEN #{statusComplete} THEN 1 ELSE 0 END)
							  THEN #{statusComplete}
							  WHEN COUNT(1) > SUM(CASE WKSTATUS WHEN #{statusCreate} THEN 1 ELSE 0 END)
							  THEN #{statusWork}
							  ELSE #{statusCreate} END
					FROM TWORK_INFO_TA_DT B
					WHERE A.CTKEY = B.CTKEY
					  AND A.TA_HDKEY = B.TA_HDKEY
		  		)
	, UPDATEDATE = #{sysdate}
	, UPDATEURKEY = #{surkey}
WHERE A.CTKEY = #{ctkey}
  AND A.TA_HDKEY = #{taHdkey}
